import{_ as e,o as d,c as o,ah as r}from"./chunks/framework.CwSw4gZW.js";const p=JSON.parse('{"title":"自定义组件开发规范","description":"","frontmatter":{},"headers":[],"relativePath":"guide/组件开发规范.md","filePath":"guide/组件开发规范.md"}'),c={name:"guide/组件开发规范.md"};function a(s,t,n,l,i,h){return d(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="自定义组件开发规范" tabindex="-1">自定义组件开发规范 <a class="header-anchor" href="#自定义组件开发规范" aria-label="Permalink to &quot;自定义组件开发规范&quot;">​</a></h1><p>本文说明使用 neo-cmp-cli 开发自定义组件时的工程目录、组件目录、目录规范、技术栈、模型配置、属性配置面板、样式与依赖等规范。</p><h2 id="_1-项目工程目录说明" tabindex="-1">1. 项目工程目录说明 <a class="header-anchor" href="#_1-项目工程目录说明" aria-label="Permalink to &quot;1. 项目工程目录说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>路径</th><th>说明</th></tr></thead><tbody><tr><td><code>src/assets/</code></td><td>静态资源；默认含 <code>css/common.scss</code>、<code>css/mixin.scss</code> 等全局可注入样式</td></tr><tr><td><code>src/assets/img/</code></td><td>图片等素材</td></tr><tr><td><code>src/components/</code></td><td><strong>自定义组件根目录</strong>；每个子目录为一个组件；可含 <code>README.md</code> 说明</td></tr><tr><td><code>src/components/&lt;组件名&gt;/</code></td><td>单个组件：<code>index.*</code>（实现）、<code>model.*</code>（设计器模型）</td></tr><tr><td><code>public/</code></td><td>本地预览用 HTML 模板、基础脚本与样式（<code>template.html</code>、<code>css/</code>、<code>scripts/</code> 等）</td></tr><tr><td><code>@types/</code></td><td>平台或工程用到的补充类型声明（如 <code>neo-ui-common</code>）</td></tr><tr><td><code>package.json</code></td><td>项目元数据、<code>framework</code>（如 <code>react-ts</code>）、脚本（<code>preview</code> / <code>linkDebug</code> / <code>pushCmp</code> 等）</td></tr><tr><td><code>tsconfig.json</code></td><td>TypeScript 编译配置（TS 模板适用）</td></tr><tr><td><code>neo.config.js</code></td><td>neo-cmp-cli 工程配置（webpack、预览、外链调试、平台地址、公共样式注入等），无需显式配置 <code>entry</code> 时，CLI 会根据 <code>src/components/</code> 下目录自动生成构建入口（可在命令行输出中查看生成的 entry）。</td></tr><tr><td><code>commitlint.config.js</code></td><td>GIT 提交信息规范（若模板启用）</td></tr><tr><td><code>.prettierrc.js</code></td><td>代码格式化规则</td></tr><tr><td><code>.npmrc</code></td><td>NPM 包管理配置，可用于添加默认的 NPM 安装源</td></tr><tr><td><code>.gitignore</code></td><td>GIT 版本控制忽略项</td></tr></tbody></table><h2 id="_2-组件目录说明" tabindex="-1">2. 组件目录说明 <a class="header-anchor" href="#_2-组件目录说明" aria-label="Permalink to &quot;2. 组件目录说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>路径</th><th>说明</th></tr></thead><tbody><tr><td><code>src/components/</code></td><td>自定义组件源码根目录</td></tr><tr><td><code>src/components/&lt;组件名&gt;/</code></td><td>单个组件目录，<strong>子目录名即组件名</strong>（<code>cmpType</code> 取值来源）</td></tr><tr><td><code>src/components/&lt;组件名&gt;/index.*</code></td><td>组件实现入口</td></tr><tr><td><code>src/components/&lt;组件名&gt;/model.*</code></td><td>组件模型文件，与页面设计器相关的配置均在此模型文件中定义</td></tr></tbody></table><h2 id="_3-组件目录规范" tabindex="-1">3. 组件目录规范 <a class="header-anchor" href="#_3-组件目录规范" aria-label="Permalink to &quot;3. 组件目录规范&quot;">​</a></h2><p>CLI 按约定扫描 <code>src/components/</code> 下的子目录与文件，发布时据此生成注册相关代码并注入构建流程，一般无需手写注册逻辑。</p><ul><li><strong>目录与命名</strong>：每个组件占有一个子目录；<strong>子目录名即组件名</strong>，并与模型中的 <code>cmpType</code>（构建时按目录名生成）保持一致。</li><li><strong>组件入口文件</strong>：目录内须包含 <code>index.ts</code> / <code>index.tsx</code> / <code>index.js</code> / <code>index.jsx</code> / <code>index.vue</code> 之一作为组件实现入口（以实际模板为准）。</li><li><strong>模型文件</strong>：目录内须包含 <code>model.ts</code> / <code>model.js</code> 作为组件模型文件。</li><li><strong>发布与注册</strong>：发布流程会生成注册相关代码并接入构建；若需手动注册，请见 <a href="https://www.npmjs.com/package/neo-register" target="_blank" rel="noreferrer">neo-register</a>。</li></ul><h2 id="_4-技术栈说明" tabindex="-1">4. 技术栈说明 <a class="header-anchor" href="#_4-技术栈说明" aria-label="Permalink to &quot;4. 技术栈说明&quot;">​</a></h2><p>当前自定义组件支持 <strong>React</strong> 与 <strong>Vue 2</strong> 两种技术栈，初始化时选择的模板决定工程依赖与组件文件后缀；构建与发布流程由 neo-cmp-cli 统一处理。</p><h3 id="_4-1-react-自定义组件" tabindex="-1">4.1 React 自定义组件 <a class="header-anchor" href="#_4-1-react-自定义组件" aria-label="Permalink to &quot;4.1 React 自定义组件&quot;">​</a></h3><p>Neo 平台前端使用 React 技术栈开发，自定义组件使用 React 技术栈开发 更容易和平台整合，自定义组件构建后的脚本资源更小（拥有更好的初次加载性能）。</p><ul><li><strong>React 版本说明</strong>：请使用 react 16 版本，与平台预置依赖对齐（参见本文「复用平台预置依赖」中的 <code>react</code> / <code>react-dom</code> 版本），避免本地与运行时版本不一致。</li><li><strong>入口文件</strong>：<code>index.tsx</code> / <code>index.jsx</code> / <code>index.ts</code> / <code>index.js</code>（与模型文件同目录）。</li><li><strong>官方文档</strong>：使用 React 开发自定义组件 和 开发 React 业务组件的方式一样，可查看以下 React 官方使用文档学习开发方式： <ul><li><a href="https://react.dev/learn" target="_blank" rel="noreferrer">React 文档（当前主站）</a></li><li><a href="https://legacy.reactjs.org/docs/getting-started.html" target="_blank" rel="noreferrer">React 16 及更早 API 说明（Legacy）</a></li></ul></li></ul><h3 id="_4-2-vue-2-自定义组件" tabindex="-1">4.2 Vue 2 自定义组件 <a class="header-anchor" href="#_4-2-vue-2-自定义组件" aria-label="Permalink to &quot;4.2 Vue 2 自定义组件&quot;">​</a></h3><p>如果团队以 Vue 2 技术栈为主、或需复用已有 Vue 2 组件逻辑时，可选用 <code>vue2</code> 技术栈开发自定义组件，CLI 内置 <code>vue2</code> 组件模板（见 <a href="./CLI使用说明.html#内置模板">CLI 使用说明 - 内置模板</a>）。</p><ul><li><strong>入口文件</strong>：一般为单文件组件 <code>index.vue</code>（具体以模板与 CLI 扫描规则为准）。</li><li><strong>暂不支持事件动作</strong>：若需要使用事件动作实现组件联动，请优先采用 <strong>React</strong> 技术栈；事件动作的概念与配置方式见 <a href="./../tools/事件动作机制.html">事件动作机制</a>。</li><li><strong>官方文档</strong>：使用 Vue 开发自定义组件 和 开发 Vue 业务组件的方式一样，可查看以下 Vue 官方使用文档学习开发方式： <ul><li><a href="https://v2.cn.vuejs.org/v2/guide/" target="_blank" rel="noreferrer">Vue 2 指南（中文）</a></li><li><a href="https://v2.vuejs.org/v2/guide/" target="_blank" rel="noreferrer">Vue 2 Guide (English)</a></li></ul></li></ul><h2 id="_5-组件模型文件属性说明" tabindex="-1">5. 组件模型文件属性说明 <a class="header-anchor" href="#_5-组件模型文件属性说明" aria-label="Permalink to &quot;5. 组件模型文件属性说明&quot;">​</a></h2><p>通过 <code>neo init</code> 或 <code>neo create cmp</code> 创建的组件会自带组件模型文件，与页面设计器相关的配置均在模型文件中定义。</p><h3 id="可配置属性一览" tabindex="-1">可配置属性一览 <a class="header-anchor" href="#可配置属性一览" aria-label="Permalink to &quot;可配置属性一览&quot;">​</a></h3><table tabindex="0"><thead><tr><th>属性名</th><th>默认值</th><th>说明</th></tr></thead><tbody><tr><td><code>cmpType</code></td><td>构建时按目录名自动生成</td><td>组件类型标识，需保证唯一</td></tr><tr><td><code>label</code></td><td>-</td><td>设计器左侧组件面板中显示的名称</td></tr><tr><td><code>description</code></td><td>-</td><td>设计器左侧组件面板中显示的描述</td></tr><tr><td><code>iconUrl</code></td><td>-</td><td>设计器左侧组件面板中显示的图标</td></tr><tr><td><code>tags</code></td><td><code>[&#39;自定义组件&#39;]</code></td><td>分类标签，决定出现在哪个分类下</td></tr><tr><td><code>exposedToDesigner</code></td><td><code>true</code></td><td>是否在页面设计器中可见</td></tr><tr><td><code>enableDuplicate</code></td><td><code>true</code></td><td>是否允许在设计器中多次拖入</td></tr><tr><td><code>targetPage</code></td><td><code>[&#39;all&#39;]</code></td><td>适配的页面类型</td></tr><tr><td><code>targetObject</code></td><td><code>[&#39;all&#39;]</code></td><td>支持的实体类型</td></tr><tr><td><code>targetApplication</code></td><td><code>[&#39;all&#39;]</code></td><td>支持的应用类型</td></tr><tr><td><code>targetDevice</code></td><td><code>&#39;all&#39;</code></td><td>支持的设备类型</td></tr><tr><td><code>defaultComProps</code></td><td>-</td><td>首次拖入页面时的默认属性</td></tr><tr><td><code>propsSchema</code></td><td><code>[]</code></td><td>数组，定义设计器右侧属性面板的配置项</td></tr></tbody></table><h3 id="页面类型-targetpage-说明" tabindex="-1">页面类型（<code>targetPage</code>）说明 <a class="header-anchor" href="#页面类型-targetpage-说明" aria-label="Permalink to &quot;页面类型（`targetPage`）说明&quot;">​</a></h3><table tabindex="0"><thead><tr><th>取值</th><th>含义</th></tr></thead><tbody><tr><td><code>all</code></td><td>所有页面类型</td></tr><tr><td><code>indexPage</code></td><td>首页</td></tr><tr><td><code>entityListPage</code></td><td>实体列表页</td></tr><tr><td><code>entityFormPage</code></td><td>实体表单页</td></tr><tr><td><code>entityDetailPage</code></td><td>实体详情页</td></tr><tr><td><code>customPage</code></td><td>自定义页面</td></tr><tr><td><code>bizPage</code></td><td>业务页面</td></tr></tbody></table><h2 id="_6-组件属性配置项" tabindex="-1">6. 组件属性配置项 <a class="header-anchor" href="#_6-组件属性配置项" aria-label="Permalink to &quot;6. 组件属性配置项&quot;">​</a></h2><p>属性配置项在组件模型文件 propsSchema 中定义，用于在<strong>页面设计器</strong>中暴露可编辑项，使业务人员无需改代码即可调整展示与行为，从而提升组件复用度。</p><h3 id="设计原则" tabindex="-1">设计原则 <a class="header-anchor" href="#设计原则" aria-label="Permalink to &quot;设计原则&quot;">​</a></h3><ul><li><strong>少而精</strong>：配置项越多，使用者理解成本越高；应优先用少量语义清晰的配置项覆盖常见定制场景，复杂逻辑可收敛为「预设模式」枚举等。</li><li><strong>与实现一致</strong>：<code>propsSchema</code> 中 <code>name</code> 对应传入组件的 <strong>props</strong> 字段名。</li><li><strong>类型与控件匹配</strong>：文本、数字、开关、枚举、颜色等应选用合适的表单项类型，便于校验与联动（见下文文档）。</li></ul><h3 id="组件代码如何使用配置项" tabindex="-1">组件代码如何使用配置项 <a class="header-anchor" href="#组件代码如何使用配置项" aria-label="Permalink to &quot;组件代码如何使用配置项&quot;">​</a></h3><ul><li><strong>React</strong>：所有属性配置项会作为 props 传入，类组件使用 <code>this.props.xxx</code>，函数组件使用函数参数或 Hooks 依赖的 props。</li><li><strong>Vue 2</strong>：一般在 <code>index.vue</code> 的 <code>props</code> 中声明同名属性，由运行时注入。</li></ul><p>当前自定义组件模型文件中可添加的属性配置类型见 <strong><a href="./../config/组件属性配置项.html">组件属性配置项</a></strong>。</p><h2 id="_7-组件样式规范" tabindex="-1">7. 组件样式规范 <a class="header-anchor" href="#_7-组件样式规范" aria-label="Permalink to &quot;7. 组件样式规范&quot;">​</a></h2><h3 id="_7-1-命名与结构" tabindex="-1">7.1 命名与结构 <a class="header-anchor" href="#_7-1-命名与结构" aria-label="Permalink to &quot;7.1 命名与结构&quot;">​</a></h3><ul><li><strong>根节点类名</strong>：最外层容器使用<strong>与组件目录名一致</strong>的类名（例如 <code>xx-cmpType</code>），其下样式写在同一 BEM 风格命名空间内，减少与其他自定义组件、平台全局样式的冲突。</li><li><strong>避免过深嵌套</strong>：优先在根作用域下使用平铺选择器（2～3 层以内为宜），便于维护与覆盖。</li><li><strong>可维护性</strong>：颜色、间距、字号等建议抽成 SCSS 变量或复用 <code>src/assets/css</code> 中的公共片段。</li></ul><h3 id="_7-2-构建时样式隔离" tabindex="-1">7.2 构建时样式隔离 <a class="header-anchor" href="#_7-2-构建时样式隔离" aria-label="Permalink to &quot;7.2 构建时样式隔离&quot;">​</a></h3><p>发布或 <code>linkDebug</code> 时，CLI 会为组件做样式隔离（默认处理组件目录下的 <code>(index|style).(scss|less)</code>），降低自定义样式对 Neo 平台全局样式的影响。</p><p>隔离方式为给样式增加作用域（如 <code>[data-scope=组件目录名]</code>）。组件根节点请使用<strong>与组件目录名一致或约定的唯一类名</strong>，否则隔离策略会因作用域不匹配而导致样式失效。</p><p>如需关闭该行为，在 <code>neo.config.js</code> 或 webpack 配置中将 <code>disableAutoAddStyleScope</code> 设为 <code>true</code>。</p><h3 id="_7-3-弹层类组件的样式" tabindex="-1">7.3 弹层类组件的样式 <a class="header-anchor" href="#_7-3-弹层类组件的样式" aria-label="Permalink to &quot;7.3 弹层类组件的样式&quot;">​</a></h3><p>Popover、Tooltip、Modal 等挂载在 <code>body</code> 等位置的 Ant Design 组件，其自定义样式建议放在组件目录下的 <code>common.scss</code> 或 <code>reset.scss</code> 中，避免与隔离策略冲突。</p><h3 id="_7-4-scss-简要使用说明" tabindex="-1">7.4 SCSS 简要使用说明 <a class="header-anchor" href="#_7-4-scss-简要使用说明" aria-label="Permalink to &quot;7.4 SCSS 简要使用说明&quot;">​</a></h3><p>工程默认支持 <strong>Sass/SCSS</strong>。组件样式内容默认放 <code>index.scss</code> / <code>style.scss</code> 中，在 JS/TS/Vue 中按模板方式引入即可。</p><p><strong>常用能力简述</strong>：</p><ul><li><strong>变量</strong>：<code>$primary-color: #1890ff;</code>，便于主题统一。</li><li><strong>嵌套</strong>：按 DOM 层级书写，注意勿嵌套过深。</li><li><strong><code>&amp;</code> 父选择器</strong>：用于伪类、修饰符，如 <code>&amp;:hover</code>、<code>.root &amp;</code>。</li><li><strong><code>@mixin</code> / <code>@include</code></strong>：抽取重复样式片段；空模板中 <code>mixin.scss</code> 可集中定义混入。</li><li><strong><code>@import</code> / <code>@use</code></strong>：拆分文件；具体语法以项目构建链支持的 Sass 版本为准。</li></ul><p><strong>全局注入</strong>：<code>neo.config.js</code> 的 <code>webpack.sassResources</code> 可将 <code>src/assets/css/common.scss</code>、<code>mixin.scss</code> 等自动注入每个 SCSS 文件，无需在每个组件重复 <code>@import</code> 公共变量与混入（修改配置后需重新启动本地调试）。</p><h2 id="_8-组件模块共享" tabindex="-1">8. 组件模块共享 <a class="header-anchor" href="#_8-组件模块共享" aria-label="Permalink to &quot;8. 组件模块共享&quot;">​</a></h2><p>多个自定义组件项目之间，可通过 <strong>模块联邦</strong> 方式在 <code>neo.config.js</code> 中配置 <code>neoCommonModule</code>：由组件 A <strong>导出</strong>共享模块，组件 B 声明 <strong>remoteDeps</strong> / <strong>externals</strong> 后按需 <strong>import</strong>，从而避免重复打包、统一维护公共逻辑。</p><p>配置步骤、数组与对象两种 <code>exports</code> 写法、与 <code>externals</code> 的配合等，见 <strong><a href="./../tools/组件模块共享.html">组件模块共享</a></strong>。</p><h2 id="_9-使用平台实体数据源" tabindex="-1">9. 使用平台实体数据源 <a class="header-anchor" href="#_9-使用平台实体数据源" aria-label="Permalink to &quot;9. 使用平台实体数据源&quot;">​</a></h2><p>自定义组件内可通过 OpenAPI SDK 访问平台实体数据，详见 <a href="./../datasource/平台实体数据源.html">平台实体数据源</a>。</p><h2 id="_10-复用平台预置依赖" tabindex="-1">10. 复用平台预置依赖 <a class="header-anchor" href="#_10-复用平台预置依赖" aria-label="Permalink to &quot;10. 复用平台预置依赖&quot;">​</a></h2><p>CLI 构建时默认会把平台已使用的依赖模块（如<code>react</code>、<code>axios</code>、<code>lodash</code>、<code>antd</code>等）作为外部依赖从打包中排除、不再重复打入构建产物，可显著缩小自定义组件包体积、提高自定义组件首次加载速度。</p><h3 id="发布时默认会剔除的平台依赖" tabindex="-1">发布时默认会剔除的平台依赖 <a class="header-anchor" href="#发布时默认会剔除的平台依赖" aria-label="Permalink to &quot;发布时默认会剔除的平台依赖&quot;">​</a></h3><p>自定义组件可直接使用下列依赖（版本需与平台一致，否则可能出现运行时问题）：</p><table tabindex="0"><thead><tr><th>依赖包</th><th>版本</th></tr></thead><tbody><tr><td>react</td><td>^16.13.1</td></tr><tr><td>react-dom</td><td>^16.13.1</td></tr><tr><td>mobx</td><td>^6.3.0</td></tr><tr><td>mobx-react</td><td>^7.0.0</td></tr><tr><td>mobx-state-tree</td><td>^5.4.0</td></tr><tr><td>axios</td><td>^0.27.2</td></tr><tr><td>classnames</td><td>^2.3.2</td></tr><tr><td>qs</td><td>^6.11.0</td></tr><tr><td>lodash</td><td>^4.17.21</td></tr><tr><td>amis</td><td>^1.1.5</td></tr><tr><td>neo-ui-common</td><td>-</td></tr></tbody></table><blockquote><p><strong>注意</strong>：请与上表版本对齐；版本不一致可能导致运行异常。</p></blockquote><h3 id="h5-端可复用的依赖" tabindex="-1">H5 端可复用的依赖 <a class="header-anchor" href="#h5-端可复用的依赖" aria-label="Permalink to &quot;H5 端可复用的依赖&quot;">​</a></h3><table tabindex="0"><thead><tr><th>依赖包</th><th>版本</th></tr></thead><tbody><tr><td>antd-mobile</td><td>2.3.4</td></tr><tr><td>neo-ui-component-h5</td><td>-</td></tr></tbody></table><p>PC / Web 端可复用的依赖</p><table tabindex="0"><thead><tr><th>依赖包</th><th>版本</th></tr></thead><tbody><tr><td>antd</td><td>4.9.4</td></tr><tr><td>@ant-design/icons</td><td>^4.8.0</td></tr><tr><td>neo-ui-component-web</td><td>-</td></tr></tbody></table><blockquote><p><strong>注意</strong>：H5 端自定义组件默认使用 antd-mobile UI 组件库，PC 端自定义组件默认使用的 antd UI 组件库。</p></blockquote>',60)])])}const u=e(c,[["render",a]]);export{p as __pageData,u as default};
